$:/plugins/bj/tiddlyprism/prismtw.css.text:
 .language-tw, .unieditor .language-tw, .unieditor .lang-tw  {
   font-family: -apple-system,BlinkMacSystemFont,Segoe UI,Helvetica,Arial,sans-serif!important;
   /*white-space:  pre-wrap;*/
 }

span.token.twhanging, span.token.twbold{
/*font-weight: bold;*/
;
  text-shadow: 0.3px 0.3px 0 currentColor;

}

.token.code_section :not(.punctuation) {
  background-color: #dcdcdc; 
  opacity:0.7;
}
 .token.transclude,.token.transcludeA, .token.twlink {
	color: #07a;
}

.token.urlstring {
	color: violet;
}
span.token.twdefs, span.token.twcode {
	color: red;
}
.token.inline_style {
  color:orange;
}
.token.strike {
  text-decoration: line-through;
}
.token.underline {
  text-decoration: underline;
}
.token.subscript > * {
  color: green; 
}
.token.superscript .content{
  color: green; 
}


.token.tw_important1 > .content ,.token.tw_important1a > .content {
 color: rgb(238, 153, 0);
}
.token.tw_important2 > .content {
 color: rgb(238, 153, 0);
}
.token.tw_important3 > .content{
 color: rgb(238, 153, 0);
} 
.token.tw_important {
}
.token.macro {
color: #905;
}

